// Originally generated by CLI Printing Press; extended in polish to support
// remote (Streamable HTTP) transport in addition to stdio per Anthropic's
// 2026-04 MCP guidance, and code-orchestration thin tools (dub_search +
// dub_execute) per the same guidance for 50+ endpoint APIs.
//
// Runtime config:
//   - DUB_MCP_TRANSPORT (stdio | http; default stdio) selects transport.
//   - DUB_MCP_ADDR (default :8080) sets the http bind address when in http mode.
//   - DUB_MCP_SURFACE (thin | full | both; default thin) selects which tool
//     surface(s) to register. Default is `thin` because the agent's tool
//     catalog tax is paid every conversation regardless of transport, and
//     dub_search + dub_execute cover the entire API in 2 tools. The 53
//     typed endpoint mirrors stay available behind DUB_MCP_SURFACE=full
//     for hosts that prefer per-tool typed argument validation.

package main

import (
	"fmt"
	"os"

	mcptools "github.com/mvanhorn/printing-press-library/library/marketing/dub/internal/mcp"

	"github.com/mark3labs/mcp-go/server"
)

func main() {
	s := server.NewMCPServer(
		"Dub",
		"1.0.0",
		server.WithToolCapabilities(false),
	)

	surface := os.Getenv("DUB_MCP_SURFACE")
	if surface == "" {
		surface = "thin"
	}
	switch surface {
	case "thin":
		mcptools.RegisterCodeOrchestrationTools(s)
	case "full":
		mcptools.RegisterTools(s)
	case "both":
		mcptools.RegisterCodeOrchestrationTools(s)
		mcptools.RegisterTools(s)
	default:
		fmt.Fprintf(os.Stderr, "Unknown DUB_MCP_SURFACE=%q (expected thin | full | both)\n", surface)
		os.Exit(2)
	}

	transport := os.Getenv("DUB_MCP_TRANSPORT")
	if transport == "" {
		transport = "stdio"
	}

	switch transport {
	case "stdio":
		if err := server.ServeStdio(s); err != nil {
			fmt.Fprintf(os.Stderr, "MCP server error: %v\n", err)
			os.Exit(1)
		}
	case "http":
		addr := os.Getenv("DUB_MCP_ADDR")
		if addr == "" {
			addr = ":8080"
		}
		http := server.NewStreamableHTTPServer(s)
		fmt.Fprintf(os.Stderr, "Dub MCP server listening (Streamable HTTP) on %s/mcp\n", addr)
		if err := http.Start(addr); err != nil {
			fmt.Fprintf(os.Stderr, "MCP HTTP server error: %v\n", err)
			os.Exit(1)
		}
	default:
		fmt.Fprintf(os.Stderr, "Unknown DUB_MCP_TRANSPORT=%q (expected stdio | http)\n", transport)
		os.Exit(2)
	}
}
